
  CREATE TABLE "DIRKSPZM32"."ISI_TEXT_TEMPLATES" 
   (	"TEXT_TEMPLATE_ID" VARCHAR2(32 CHAR) DEFAULT sys_guid() NOT NULL ENABLE, 
	"LANGUAGE_CODE" VARCHAR2(5 CHAR) NOT NULL ENABLE, 
	"TEXT_CATEGORY" VARCHAR2(50 CHAR) NOT NULL ENABLE, 
	"TEXT_GROUP" VARCHAR2(255 CHAR), 
	"TEMPLATE_NAME" VARCHAR2(50 CHAR) NOT NULL ENABLE, 
	"TAGS" VARCHAR2(255 CHAR), 
	"TEXT_TEMPLATE" CLOB NOT NULL ENABLE, 
	"CREATED_BY_LOGIN_ID" NUMBER(*,0) NOT NULL ENABLE, 
	"CREATED_DATE" DATE DEFAULT sysdate NOT NULL ENABLE, 
	"LAST_MODIFIED_BY_LOGIN_ID" NUMBER(*,0) NOT NULL ENABLE, 
	"LAST_MODIFIED_DATE" DATE DEFAULT sysdate NOT NULL ENABLE
   ) ;
ALTER TABLE "DIRKSPZM32"."ISI_TEXT_TEMPLATES" ADD CONSTRAINT "PK_TEXT_TEMPLATES" PRIMARY KEY ("TEXT_TEMPLATE_ID")
  USING INDEX  ENABLE;
ALTER TABLE "DIRKSPZM32"."ISI_TEXT_TEMPLATES" ADD CONSTRAINT "TEXT_LANG_CODE_LOWERCASE" CHECK (language_code = lower(language_code)) ENABLE;
ALTER TABLE "DIRKSPZM32"."ISI_TEXT_TEMPLATES" ADD CONSTRAINT "UK_TEXT_TEMPLATES" UNIQUE ("TEXT_CATEGORY", "LANGUAGE_CODE", "TEMPLATE_NAME")
  USING INDEX  ENABLE;
ALTER TABLE "DIRKSPZM32"."ISI_TEXT_TEMPLATES" ADD CONSTRAINT "VALID_TEXT_CATEGORIES" CHECK (text_category in ('WM', 'MM', 'PD', 'HR')) ENABLE;


